#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

long long inv(long long a, long long mod) {
    return powmod(a, mod - 2, mod);
}

long long choose(long long n, long long k, long long mod) {
    long long res = 1;
    for (long long i = 1; i <= k; i++) {
        res = (res * (n - i + 1)) % mod;
        res = (res * inv(i, mod)) % mod;
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long n, p;
        scanf("%lld %lld", &n, &p);
        long long ans = 0;
        for (long long k = 0; k <= n; k++) {
            long long res = choose(n, k, p);
            if (res != 0) ans = (ans + 1) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

