const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
function powmod(a, b, mod) {
    let res = 1;
    while (b > 0) {
        if (b % 2 === 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b = Math.floor(b / 2);
    }
    return res;
}
function inv(a, mod) {
    return powmod(a, mod - 2, mod);
}
function choose(n, k, mod) {
    let res = 1;
    for (let i = 1; i <= k; i++) {
        res = (res * (n - i + 1)) % mod;
        res = (res * inv(i, mod)) % mod;
    }
    return res;
}
function nextLine() {
    return lines[idx++];
}
let T = parseInt(nextLine());
while (T-- > 0) {
    let [n, p] = nextLine().split(' ').map(Number);
    let ans = 0;
    for (let k = 0; k <= n; k++) {
        let res = choose(n, k, p);
        if (res !== 0) ans = (ans + 1) % MOD;
    }
    console.log(ans);
}

